const updaterUrl = "https://cdn.jsdelivr.net/gh/deepsleep-claw/SleepTavernHome@script-updater-v1.0.0/dist/%E5%85%AC%E5%85%B1%E6%A8%A1%E5%9D%97/%E8%84%9A%E6%9C%AC%E6%9B%B4%E6%96%B0%E5%99%A8/index.js";
const config = {
  "pluginId": "modern-ui",
  "pluginName": "现代化界面",
  "repository": "deepsleep-claw/SleepTavernHome",
  "manifestUrl": "https://raw.githubusercontent.com/deepsleep-claw/SleepTavernHome/main/manifest.json",
  "cdnBaseUrl": "https://cdn.jsdelivr.net/gh",
  "channel": "stable",
  "tagPrefix": "modern-ui-v",
  "updaterApiMajor": 1,
  "fallback": {
    "version": "0.1.3",
    "tag": "modern-ui-v0.1.3",
    "entry": "dist/酒馆助手/现代化界面/index.js",
    "url": "https://cdn.jsdelivr.net/gh/deepsleep-claw/SleepTavernHome@modern-ui-v0.1.3/dist/%E9%85%92%E9%A6%86%E5%8A%A9%E6%89%8B/%E7%8E%B0%E4%BB%A3%E5%8C%96%E7%95%8C%E9%9D%A2/index.js",
    "updaterApiMajor": 1
  }
};
const describeError = error => error instanceof Error && error.message ? error.message : String(error || '未知错误');

try {
  const updater = await import(updaterUrl);
  if (updater.UPDATER_API_MAJOR !== 1) {
    throw new Error(`更新器 API 不兼容：需要 v1，实际为 v${updater.UPDATER_API_MAJOR ?? '未知'}`);
  }
  if (updater.UPDATER_VERSION !== "1.0.0") {
    throw new Error(`更新器版本不匹配：需要 1.0.0，实际为 ${updater.UPDATER_VERSION ?? '未知'}`);
  }
  if (typeof updater.bootPlugin !== 'function') {
    throw new Error('更新器没有导出 bootPlugin()');
  }
  await updater.bootPlugin(config);
} catch (error) {
  console.error(`[${config.pluginName}] 启动失败。`, error);
  if (typeof toastr !== 'undefined') {
    toastr.error(`启动失败：${describeError(error)}`, config.pluginName);
  }
}
